#!/usr/bin/env php
<?php
declare(strict_types=1);
use App\Core\Env;use App\Core\Database;
require dirname(__DIR__).'/app/core/Env.php';Env::load(dirname(__DIR__).'/.env');spl_autoload_register(function($c){$p='App\\';if(!str_starts_with($c,$p))return;$f=dirname(__DIR__).'/app/'.str_replace('\\','/',substr($c,strlen($p))).'.php';if(is_file($f))require $f;});$pdo=Database::connection();$rows=$pdo->query("SELECT r.*,w.provider,w.event_type,w.payload FROM webhook_replays r JOIN webhook_events w ON w.id=r.webhook_event_id WHERE r.status='queued' LIMIT 50")->fetchAll();foreach($rows as $r){try{$pdo->prepare('UPDATE webhook_events SET status=\'received\',attempts=attempts+1,error_message=NULL WHERE id=?')->execute([$r['webhook_event_id']]);if($r['provider']==='stripe'){$result='Stripe event reset for provider processing/manual verification.';}elseif($r['provider']==='graph'){$pdo->prepare("INSERT INTO communication_queue(channel,action,payload,status) VALUES('calendar','graph_notification',?,'pending')")->execute([$r['payload']]);$result='Graph notification requeued.';}else{$result='Event reset for provider-specific worker.';}$pdo->prepare("UPDATE webhook_replays SET status='completed',result_text=?,completed_at=NOW() WHERE id=?")->execute([$result,$r['id']]);}catch(Throwable $e){$pdo->prepare("UPDATE webhook_replays SET status='failed',result_text=?,completed_at=NOW() WHERE id=?")->execute([$e->getMessage(),$r['id']]);}}echo 'Processed '.count($rows)." webhook replay(s).\n";
